import{parseArgs}from"node:util";import{Plugins}from"./plugins/index.js";import{timerify}from"./util/Performance.js";const PMap=Plugins,{values:values}=parseArgs({strict:!1,options:{performance:{type:"boolean"}}}),isEnabled=!!values.performance,timerifyMethods=["resolve","resolveConfig","resolveAST"],PluginEntries=Object.entries(PMap);if(isEnabled)for(const[,r]of PluginEntries)for(const e of timerifyMethods)e in r&&(r[e]=timerify(r[e],`${e} (${r.title})`));const pluginArgsMap=new Map(PluginEntries.flatMap(([r,e])=>{if(!e.args)return[];const i=[r,e.args];return Array.isArray(e.args?.binaries)?e.args.binaries.map(r=>[r,i]):[[r,i]]}));export{PMap as Plugins,PluginEntries,pluginArgsMap};